import { CardHeader, IconButton, Typography } from '@material-ui/core'
import React from 'react'

export default function Card({ subject }) {
    return (
        <div>
            <Typography>
                <Card>
                    <CardHeader
                        action={
                            <IconButton>
                                <MoreVertIcon  />
                            </IconButton>
                        }
                    />
                </Card>
            </Typography>
        </div>
    )
}
